    42→  mode: 'single' | 'batch' | 'date-range';
    43→  messageId?: string;
    44→  limit?: number;
    45→  startDate?: string;
    46→  endDate?: string;
    47→  dryRun: boolean;
    48→}
    49→
    50→/**
    51→ * Processing summary statistics
    52→ */
    53→export interface ProcessingSummary {
    54→  totalEmails: number;
    55→  success: number;
    56→  errors: number;
