    78→      if (i + 1 >= args.length) {
    79→        throw new Error('Missing value for --mode argument');
    80→      }
    81→      result.mode = args[++i] as 'single' | 'batch' | 'date-range';
    82→      break;
    83→    case '--message-id':
    84→      if (i + 1 >= args.length) {
    85→        throw new Error('Missing value for --message-id argument');
    86→      }
    87→      result.messageId = args[++i];
    88→      break;
    89→    case '--limit':
    90→      if (i + 1 >= args.length) {
    91→        throw new Error('Missing value for --limit argument');
    92→      }
    93→      result.limit = parseInt(args[++i], 10);
    94→      break;
    95→    case '--start':
    96→      if (i + 1 >= args.length) {
    97→        throw new Error('Missing value for --start argument');
    98→      }
    99→      result.startDate = args[++i];
   100→      break;
   101→    case '--end':
   102→      if (i + 1 >= args.length) {
   103→        throw new Error('Missing value for --end argument');
   104→      }
   105→      result.endDate = args[++i];
   106→      break;
   107→    case '--dry-run':
   108→      result.dryRun = true;
   109→      break;
   110→    }
   111→  }
   112→
   113→  // Validate required arguments
   114→  if (!result.mode) {
   115→    throw new Error('Mode is required (--mode single|batch|date-range)');
   116→  }
   117→
   118→  if (!['single', 'batch', 'date-range'].includes(result.mode)) {
   119→    throw new Error('Invalid mode. Must be: single, batch, or date-range');
   120→  }
   121→
   122→  if (result.mode === 'single' && !result.messageId) {
   123→    throw new Error('message-id is required for single mode (--message-id <id>)');
   124→  }
   125→
   126→  if (result.mode === 'date-range') {
   127→    if (!result.startDate || !result.endDate) {
   128→      throw new Error(
