   171→ * Process single email through classification pipeline
   172→ *
   173→ * @param messageId - Gmail message ID
   174→ * @param config - Processing configuration
   175→ * @param dryRun - If true, skip persistence
   176→ * @returns Processing summary
   177→ */
   178→export async function processSingleEmail(
   179→  messageId: string,
   180→  config: ProcessingConfig,
   181→  dryRun: boolean
   182→): Promise<ProcessingSummary> {
   183→  const summary: ProcessingSummary = {
   184→    totalEmails: 1,
   185→    success: 0,
   186→    errors: 0,
   187→    totalDurationMs: 0,
   188→    errorDetails: [],
   189→  };
   190→
   191→  const startTime = Date.now();
   192→
   193→  try {
   194→    // 1. Fetch email from database
   195→    console.log(`Fetching email: ${messageId}`);
   196→    const email = await fetchEmailById(messageId);
   197→
   198→    // 2. Initialize pipeline
   199→    const pipeline = new ClassificationPipeline(config);
   200→
   201→    // 3. Classify email
   202→    console.log(`Classifying: [${email.id}] ${email.subject}`);
   203→    const result = await pipeline.classify(email);
   204→
   205→    // 4. Output result
   206→    console.log(formatEmailOutput(email, result));
   207→
   208→    // 5. Persist result (unless dry-run)
   209→    if (!dryRun) {
   210→      await saveClassificationResult(messageId, result);
   211→      console.log(`Persisted classification result for ${messageId}`);
   212→    } else {
   213→      console.log(`[DRY RUN] Skipped persistence for ${messageId}`);
   214→    }
   215→
   216→    // 6. Write explainability trace
   217→    const tracePath = await writeExplainabilityTrace(email, result);
   218→    console.log(`Explainability trace: ${tracePath}`);
   219→
   220→    summary.success = 1;
   221→    summary.totalDurationMs = Date.now() - startTime;
   222→  } catch (error) {
   223→    summary.errors = 1;
   224→    summary.totalDurationMs = Date.now() - startTime;
   225→    summary.errorDetails.push({
   226→      messageId,
   227→      error: error instanceof Error ? error.message : String(error),
   228→    });
   229→
   230→    console.error(`Error processing ${messageId}: ${error instanceof Error ? error.message : String(error)}`);
   231→  }
   232→
   233→  return summary;
   234→}
   235→
   236→/**
   237→ * Process batch of unclassified emails
   238→ *
   239→ * @param limit - Maximum number of emails to process
   240→ * @param config - Processing configuration
   241→ * @param dryRun - If true, skip persistence
   242→ * @returns Processing summary
   243→ */
   244→export async function processBatchEmails(
   245→  limit: number,
   246→  config: ProcessingConfig,
   247→  dryRun: boolean
   248→): Promise<ProcessingSummary> {
   249→  const summary: ProcessingSummary = {
   250→    totalEmails: 0,
   251→    success: 0,
   252→    errors: 0,
   253→    totalDurationMs: 0,
