   269→      summary.totalDurationMs = Date.now() - startTime;
   270→      return summary;
   271→    }
   272→
   273→    // 2. Initialize pipeline
   274→    const pipeline = new ClassificationPipeline(config);
   275→
   276→    // 3. Process each email
   277→    for (const email of emails) {
   278→      try {
   279→        console.log(`Classifying [${email.id}] ${email.subject}`);
   280→        const result = await pipeline.classify(email);
