   298→        console.error(`Error processing ${email.id}: ${error instanceof Error ? error.message : String(error)}`);
   299→      }
   300→    }
   301→
   302→    summary.totalDurationMs = Date.now() - startTime;
   303→  } catch (error) {
   304→    console.error(`Fatal error in batch processing: ${error instanceof Error ? error.message : String(error)}`);
   305→    throw error;
   306→  }
   307→
   308→  return summary;
   309→}
   310→
   311→/**
   312→ * Process emails within date range
   313→ *
   314→ * @param startDate - Start date (YYYY-MM-DD)
   315→ * @param endDate - End date (YYYY-MM-DD)
   316→ * @param limit - Maximum number of emails to process
   317→ * @param config - Processing configuration
   318→ * @param dryRun - If true, skip persistence
   319→ * @returns Processing summary
   320→ */
   321→export async function processDateRangeEmails(
   322→  startDate: string,
   323→  endDate: string,
   324→  limit: number,
   325→  config: ProcessingConfig,
   326→  dryRun: boolean
   327→): Promise<ProcessingSummary> {
   328→  const summary: ProcessingSummary = {
   329→    totalEmails: 0,
   330→    success: 0,
   331→    errors: 0,
   332→    totalDurationMs: 0,
   333→    errorDetails: [],
   334→  };
   335→
   336→  const startTime = Date.now();
   337→
   338→  try {
   339→    // Parse and validate dates
   340→    const start = new Date(startDate);
   341→    const end = new Date(endDate);
   342→
   343→    // Validate dates are valid
   344→    if (isNaN(start.getTime()) || isNaN(end.getTime())) {
   345→      throw new Error('Invalid date format. Use YYYY-MM-DD format for dates');
   346→    }
   347→
   348→    if (start > end) {
   349→      throw new Error('Invalid date range: start date must be before end date');
   350→    }
   351→
   352→    // 1. Fetch emails by date range
   353→    console.log(`Fetching emails from ${startDate} to ${endDate} (limit: ${limit})...`);
   354→    const emails = await fetchEmailsByDateRange(start, end, limit);
   355→
   356→    summary.totalEmails = emails.length;
   357→    console.log(`Found ${emails.length} emails to process\n`);
   358→
   359→    if (emails.length === 0) {
   360→      console.log('No emails found in date range.');
   361→      summary.totalDurationMs = Date.now() - startTime;
   362→      return summary;
   363→    }
   364→
   365→    // 2. Initialize pipeline
   366→    const pipeline = new ClassificationPipeline(config);
   367→
   368→    // 3. Process each email
   369→    for (const email of emails) {
   370→      try {
   371→        console.log(`Classifying [${email.id}] ${email.subject}`);
   372→        const result = await pipeline.classify(email);
   373→
   374→        console.log(formatEmailOutput(email, result));
   375→
   376→        if (!dryRun) {
   377→          await saveClassificationResult(email.id, result);
   378→        }
   379→
   380→        await writeExplainabilityTrace(email, result);
   381→
   382→        summary.success++;
   383→      } catch (error) {
   384→        summary.errors++;
   385→        summary.errorDetails.push({
   386→          messageId: email.id,
   387→          error: error instanceof Error ? error.message : String(error),
   388→        });
   389→
   390→        console.error(`Error processing ${email.id}: ${error instanceof Error ? error.message : String(error)}`);
   391→      }
   392→    }
   393→
   394→    summary.totalDurationMs = Date.now() - startTime;
   395→  } catch (error) {
   396→    console.error(`Fatal error in date range processing: ${error instanceof Error ? error.message : String(error)}`);
   397→    throw error;
   398→  }
   399→
   400→  return summary;
   401→}
   402→
   403→/**
   404→ * Format per-email output line
   405→ *
   406→ * @param email - Email message
   407→ * @param result - Classification result
   408→ * @returns Formatted output string
   409→ */
   410→export function formatEmailOutput(email: EmailMessage, result: ClassificationResult): string {
   411→  const labels = result.selectedLabels.map((label) => label.subtype || label.category).join(', ');
   412→  const primaryLabel = result.selectedLabels.find((l) => l.isPrimary);
   413→  const confidence = primaryLabel ? primaryLabel.confidence.toFixed(2) : '0.00';
   414→  const durationSec = (result.processingDurationMs / 1000).toFixed(1);
   415→
   416→  return `[${email.id}] ${email.subject} → labels: [${labels || 'none'}] (confidence: ${confidence}) - ${durationSec}s`;
   417→}
   418→
   419→/**
   420→ * Format summary statistics
   421→ *
   422→ * @param summary - Processing summary
   423→ * @returns Formatted summary string
   424→ */
   425→export function formatSummary(summary: ProcessingSummary): string {
   426→  const totalSec = (summary.totalDurationMs / 1000).toFixed(1);
   427→  const avgSec = summary.totalEmails > 0 ? (summary.totalDurationMs / 1000 / summary.totalEmails).toFixed(2) : '0.00';
   428→
   429→  let output = `\n${'='.repeat(80)}\n`;
   430→  output += `Processed ${summary.totalEmails} emails in ${totalSec}s (avg ${avgSec}s/email)\n`;
   431→  output += `${summary.success} success, ${summary.errors} errors\n`;
   432→
   433→  if (summary.errorDetails.length > 0) {
   434→    output += '\nErrors:\n';
   435→    for (const error of summary.errorDetails) {
   436→      output += `  - [${error.messageId}] ${error.error}\n`;
   437→    }
   438→  }
   439→
   440→  output += `${'='.repeat(80)}\n`;
   441→
   442→  return output;
   443→}
   444→
   445→/**
   446→ * Write explainability trace to file
   447→ *
   448→ * @param email - Email message
   449→ * @param result - Classification result
   450→ * @returns Path to written trace file
   451→ */
   452→export async function writeExplainabilityTrace(email: EmailMessage, result: ClassificationResult): Promise<string> {
   453→  // Create timestamped output directory
   454→  const timestamp = new Date().toISOString().replace(/[:.]/g, '-').split('.')[0].replace('T', '-');
   455→  const outputDir = join(process.cwd(), 'test-pipeline-results', timestamp);
   456→
   457→  await fs.mkdir(outputDir, { recursive: true });
   458→
   459→  // Write trace JSON
   460→  const tracePath = join(outputDir, `${email.id}.json`);
   461→  const trace = {
   462→    messageId: email.id,
   463→    subject: email.subject,
   464→    from: email.from.email,
   465→    date: email.date,
   466→    classificationResult: result,
   467→    timestamp: new Date().toISOString(),
   468→  };
   469→
   470→  await fs.writeFile(tracePath, JSON.stringify(trace, null, 2));
   471→
   472→  return tracePath;
   473→}
   474→
   475→/**
   476→ * Main CLI entry point
   477→ *
   478→ * @param args - Command line arguments
   479→ * @returns Exit code (0 = success, 1 = error)
   480→ */
   481→export async function runTestPipeline(args: string[]): Promise<number> {
   482→  try {
   483→    // 1. Parse arguments
   484→    const cliArgs = parseArguments(args);
   485→
   486→    console.log(`\nTest Pipeline - Mode: ${cliArgs.mode}${cliArgs.dryRun ? ' [DRY RUN]' : ''}\n`);
   487→
   488→    // 2. Load configuration
   489→    console.log('Loading configuration...');
   490→    const config = await loadConfiguration();
   491→    console.log('Configuration loaded successfully\n');
   492→
   493→    // 3. Process based on mode
   494→    let summary: ProcessingSummary;
   495→
   496→    switch (cliArgs.mode) {
   497→    case 'single':
   498→      summary = await processSingleEmail(cliArgs.messageId!, config, cliArgs.dryRun);
   499→      break;
   500→
   501→    case 'batch':
   502→      summary = await processBatchEmails(cliArgs.limit || 10, config, cliArgs.dryRun);
   503→      break;
   504→
   505→    case 'date-range':
   506→      summary = await processDateRangeEmails(
   507→          cliArgs.startDate!,
   508→          cliArgs.endDate!,
   509→          cliArgs.limit || 100,
   510→          config,
   511→          cliArgs.dryRun
   512→      );
   513→      break;
   514→    }
   515→
   516→    // 4. Print summary
   517→    console.log(formatSummary(summary));
   518→
   519→    // 5. Cleanup
   520→    await closeQueryPool();
   521→    await closeWriterPool();
   522→
   523→    // 6. Return exit code
   524→    return summary.errors > 0 ? 1 : 0;
   525→  } catch (error) {
   526→    console.error(`\nFatal error: ${error instanceof Error ? error.message : String(error)}`);
   527→
   528→    // Cleanup on error
   529→    try {
   530→      await closeQueryPool();
   531→      await closeWriterPool();
   532→    } catch {
   533→      // Ignore cleanup errors
   534→    }
   535→
   536→    return 1;
   537→  }
   538→}
   539→
   540→/**
   541→ * CLI execution (only when run directly)
   542→ */
   543→if (require.main === module) {
   544→  runTestPipeline(process.argv.slice(2))
   545→    .then((exitCode) => {
   546→      process.exit(exitCode);
   547→    })
   548→    .catch((error) => {
   549→      console.error('Unexpected error:', error);
   550→      process.exit(1);
   551→    });
   552→}
