#!/usr/bin/env node
/**
 * Fix email-categorizer-config.json validation errors
 *
 * Brings legacy config into compliance with new Zod schemas by:
 * 1. Adding required metadata fields
 * 2. Normalizing weights to 0.0-1.0 range
 * 3. Adding missing tuning_parameters
 * 4. Adding missing performance settings
 * 5. Fixing field enum issues
 * 6. Adding missing ai_final_classification
 * 7. Adding attribute descriptions
 */

const fs = require('fs');
const path = require('path');
const crypto = require('crypto');

const configPath = path.join(__dirname, '../config/email-categorizer-config.json');
const config = JSON.parse(fs.readFileSync(configPath, 'utf8'));

console.log('Fixing configuration validation errors...\n');

// Track changes
const changes = [];

// Helper to scale weights proportionally from old range to 0.0-1.0
// Old range appears to be 0-15 based on high_confidence_threshold
const OLD_MAX = 15;
function scaleWeight(oldValue) {
  return Math.min(1.0, Math.max(0.0, oldValue / OLD_MAX));
}

// 1. Fix settings.rule_scoring - add missing tuning_parameters
if (!config.processing_config.settings.rule_scoring.tuning_parameters) {
  config.processing_config.settings.rule_scoring.tuning_parameters = {
    K_high: 1.0,
    K_medium: 0.7,
    K_low: 0.3,
    aggregation_cap: 1.0
  };
  changes.push('Added settings.rule_scoring.tuning_parameters');
}

// 2. Fix settings.attribute_influence - add missing tuning_parameters
if (!config.processing_config.settings.attribute_influence.tuning_parameters) {
  config.processing_config.settings.attribute_influence.tuning_parameters = {
    bonus_multiplier: 1.0,
    penalty_multiplier: 1.0,
    max_total_bonus: 0.5,
    max_total_penalty: 0.3
  };
  changes.push('Added settings.attribute_influence.tuning_parameters');
}

// 3. Add missing performance settings
if (!config.processing_config.settings.performance) {
  config.processing_config.settings.performance = {
    parallel_processing: true,
    max_parallel_emails: 10,
    batch_size: 50,
    enable_caching: true,
    cache_ttl_seconds: 3600
  };
  changes.push('Added settings.performance');
}

// 4. Fix confidence_gap_threshold (2 → 0.13)
config.processing_config.settings.disambiguation.confidence_gap_threshold = scaleWeight(2);
changes.push(`Fixed disambiguation.confidence_gap_threshold: 2 → ${scaleWeight(2)}`);

// 5. Fix multi_label_selection thresholds
config.processing_config.settings.multi_label_selection.min_secondary_confidence = scaleWeight(8);
changes.push(`Fixed multi_label_selection.min_secondary_confidence: 8 → ${scaleWeight(8)}`);

// 6. Fix ai_routing thresholds
config.processing_config.settings.ai_routing.high_confidence_threshold = scaleWeight(15);
config.processing_config.settings.ai_routing.ai_required_threshold = scaleWeight(12);
changes.push(`Fixed ai_routing.high_confidence_threshold: 15 → ${scaleWeight(15)}`);
changes.push(`Fixed ai_routing.ai_required_threshold: 12 → ${scaleWeight(12)}`);

// 7. Fix confidence_thresholds (all values)
const oldThresholds = { ...config.processing_config.confidence_thresholds };
config.processing_config.confidence_thresholds = {
  high_confidence: scaleWeight(oldThresholds.high_confidence),
  medium_confidence: scaleWeight(oldThresholds.medium_confidence),
  low_confidence: scaleWeight(oldThresholds.low_confidence),
  ai_classification_required: scaleWeight(oldThresholds.ai_classification_required),
  manual_review_required: scaleWeight(oldThresholds.manual_review_required),
  secondary_label_min_gap: scaleWeight(oldThresholds.secondary_label_min_gap)
};
changes.push('Normalized all confidence_thresholds to 0.0-1.0 range');

// 8. Fix multi_label_policy thresholds
const oldPolicy = { ...config.processing_config.multi_label_policy };
config.processing_config.multi_label_policy.min_confidence_for_additional = scaleWeight(oldPolicy.min_confidence_for_additional);
config.processing_config.multi_label_policy.min_delta_primary_secondary = scaleWeight(oldPolicy.min_delta_primary_secondary);
changes.push('Normalized multi_label_policy thresholds to 0.0-1.0 range');

// 9. Fix all rule weights in subtypes
function fixRuleWeights(obj, path = '') {
  if (!obj || typeof obj !== 'object') return;

  if (obj.weight !== undefined && obj.weight > 1) {
    const oldWeight = obj.weight;
    obj.weight = scaleWeight(oldWeight);
    changes.push(`Normalized weight at ${path}: ${oldWeight} → ${obj.weight.toFixed(4)}`);
  }

  for (const [key, value] of Object.entries(obj)) {
    if (typeof value === 'object' && value !== null) {
      fixRuleWeights(value, path ? `${path}.${key}` : key);
    }
  }
}

fixRuleWeights(config.processing_config.top_level_categories, 'top_level_categories');

// 10. Fix field enum: headers.list-unsubscribe → headers
function fixFieldEnums(obj, path = '') {
  if (!obj || typeof obj !== 'object') return;

  if (obj.field === 'headers.list-unsubscribe') {
    obj.field = 'headers';
    obj.operation = 'exists'; // Ensure operation is compatible
    changes.push(`Fixed field enum at ${path}: 'headers.list-unsubscribe' → 'headers'`);
  }

  for (const [key, value] of Object.entries(obj)) {
    if (typeof value === 'object' && value !== null) {
      fixFieldEnums(value, path ? `${path}.${key}` : key);
    }
  }
}

fixFieldEnums(config.processing_config, 'processing_config');

// 11. Add missing ai_final_classification for categories
const categoriesNeedingAI = ['account_security', 'system_notifications', 'scheduling_events', 'marketing_promotions', 'uncategorized'];

for (const category of categoriesNeedingAI) {
  const catDef = config.processing_config.top_level_categories[category];
  if (catDef && !catDef.ai_final_classification) {
    // Generate appropriate ai_final_classification based on category
    const aiClassifications = {
      account_security: {
        category_description: 'Account or security related alerts, password resets, login notifications.',
        decision_criteria: [
          'Does email reference account security, login, or authentication?',
          'Is there a password reset or credential change request?',
          'Does it contain security advisory or policy update information?'
        ],
        exclusion_criteria: ['Generic marketing or promotional content']
      },
      system_notifications: {
        category_description: 'Service/platform system operational notifications and updates.',
        decision_criteria: [
          'Is it a system, service, or platform operational notification?',
          'Does it announce feature changes or product updates?',
          'Is there quota, usage, or service status information?'
        ],
        exclusion_criteria: ['User-generated content', 'Transactional communications']
      },
      scheduling_events: {
        category_description: 'Calendar & event logistics (invites, updates).',
        decision_criteria: [
          'Is it a calendar invitation or meeting request?',
          'Does it contain event timing or scheduling information?',
          'Is there a change to a scheduled event?'
        ],
        exclusion_criteria: ['Travel itineraries (should be travel category)']
      },
      marketing_promotions: {
        category_description: 'Promotional or sales-oriented content.',
        decision_criteria: [
          'Is primary intent promotional or sales-oriented?',
          'Does it contain discount, sale, or special offer language?',
          'Is there marketing content without transactional elements?'
        ],
        exclusion_criteria: ['Transactional receipts or invoices']
      },
      uncategorized: {
        category_description: 'Fallback when no confident category applies.',
        decision_criteria: [
          'Does the email not fit clearly into any other category?',
          'Is classification confidence low across all categories?',
          'Would manual review provide better categorization?'
        ],
        exclusion_criteria: []
      }
    };

    catDef.ai_final_classification = aiClassifications[category];
    changes.push(`Added ai_final_classification for ${category}`);
  }
}

// 12. Add missing attribute descriptions
const missingDescriptions = {
  requires_action: 'Indicates email requires user action or response',
  has_amount: 'Email contains monetary amounts or financial figures',
  has_due_date: 'Email contains due date or payment deadline',
  tracking_present: 'Email contains package tracking information',
  unsubscribe_present: 'Email contains unsubscribe link or preference management'
};

for (const [attrName, description] of Object.entries(missingDescriptions)) {
  if (config.processing_config.attributes.schema[attrName]) {
    if (!config.processing_config.attributes.schema[attrName].description) {
      config.processing_config.attributes.schema[attrName].description = description;
      changes.push(`Added description for attribute: ${attrName}`);
    }
  }
}

// 13. Ensure category_roles exists in _roles_legend (it already does, no changes needed)
// The schema shows it's already present with all required roles

// 14. Fix attribute_bonus_map values (scale to 0.0-1.0 range)
// The bonus values appear to be on a 0-5 scale, let's keep them as multipliers since they're not probabilities
// Actually, looking at the schema, attribute bonuses use WeightSchema which allows 0-1, so we need to scale these too
function scaleAttributeBonus(oldValue) {
  // Attribute bonuses seem to be on 0-5 scale based on personal.self_sent: 5
  // Let's scale to 0-1 range
  const BONUS_MAX = 5;
  return Math.min(1.0, Math.max(0.0, oldValue / BONUS_MAX));
}

function fixAttributeBonuses(obj, path = '') {
  if (!obj || typeof obj !== 'object') return;

  for (const [key, value] of Object.entries(obj)) {
    if (typeof value === 'number' && value > 1) {
      const oldValue = value;
      obj[key] = scaleAttributeBonus(oldValue);
      changes.push(`Normalized attribute bonus at ${path}.${key}: ${oldValue} → ${obj[key].toFixed(4)}`);
    } else if (typeof value === 'object' && value !== null) {
      fixAttributeBonuses(value, path ? `${path}.${key}` : key);
    }
  }
}

fixAttributeBonuses(config.processing_config.attributes.attribute_bonus_map, 'attributes.attribute_bonus_map');

// 15. Generate hash of the processing_config
const processingConfigStr = JSON.stringify(config.processing_config, null, 2);
const hash = crypto.createHash('sha256').update(processingConfigStr).digest('hex');

// 16. Add root-level metadata
const fixedConfig = {
  version: '2.0.0',
  lastModified: new Date().toISOString(),
  hash: hash,
  processing_config: config.processing_config,
  schemaVersion: '1.0.0',
  validationPassed: false,
  validationErrors: []
};

// Write fixed config
fs.writeFileSync(configPath, JSON.stringify(fixedConfig, null, 2) + '\n', 'utf8');

console.log('Configuration fixed successfully!\n');
console.log('Changes made:');
changes.forEach((change, i) => console.log(`  ${i + 1}. ${change}`));
console.log(`\nTotal changes: ${changes.length}`);
console.log(`\nConfig hash: ${hash}`);
console.log(`Config version: 2.0.0`);
console.log(`Last modified: ${fixedConfig.lastModified}`);

