/**
 * Validate the fixed configuration against Zod schemas
 */

import { readFileSync } from 'fs';
import { join } from 'path';
import { CategoryConfigurationSchema } from '../packages/classification-engine/src/config/category-config-schema.js';

const configPath = join(process.cwd(), 'config', 'email-categorizer-config.json');
const configData = JSON.parse(readFileSync(configPath, 'utf8'));

console.log('Validating fixed configuration against Zod schemas...\n');

try {
  const validatedConfig = CategoryConfigurationSchema.parse(configData);
  console.log('SUCCESS: Configuration is valid!');
  console.log(`\nConfiguration summary:`);
  console.log(`  - Version: ${validatedConfig.version}`);
  console.log(`  - Last Modified: ${validatedConfig.lastModified}`);
  console.log(`  - Hash: ${validatedConfig.hash.substring(0, 16)}...`);
  console.log(`  - Processing Config Version: ${validatedConfig.processing_config.version}`);
  console.log(`  - Top-Level Categories: ${Object.keys(validatedConfig.processing_config.top_level_categories).length}`);
  console.log(`  - Attributes Defined: ${Object.keys(validatedConfig.processing_config.attributes.schema).length}`);
  console.log(`\nAll validation checks passed!`);
  process.exit(0);
} catch (error: any) {
  console.error('VALIDATION FAILED:\n');
  if (error.errors) {
    error.errors.forEach((err: any, index: number) => {
      console.error(`${index + 1}. ${err.path.join('.')}:`);
      console.error(`   ${err.message}`);
    });
    console.error(`\nTotal errors: ${error.errors.length}`);
  } else {
    console.error(error);
  }
  process.exit(1);
}

