    "attributes": {
      "schema": {
        "explicitness": {
          "type": "enum",
          "values": [
            "explicit",
            "implicit"
          ],
          "description": "Nature of action request if actionable."
        },
        "urgency": {
          "type": "enum",
          "values": [
            "none",
            "low",
            "medium",
