cd /workspaces/gmail-automation && node -e "
const crypto = require('crypto');
const fs = require('fs');
const path = require('path');

const configPath = path.join(process.cwd(), 'config', 'email-categorizer-config.json');
const config = JSON.parse(fs.readFileSync(configPath, 'utf8'));

// Regenerate hash from processing_config
const processingConfigStr = JSON.stringify(config.processing_config, null, 2);
const newHash = crypto.createHash('sha256').update(processingConfigStr).digest('hex');

// Update hash and timestamp
config.hash = newHash;
config.lastModified = new Date().toISOString();

// Write back
fs.writeFileSync(configPath, JSON.stringify(config, null, 2) + '\n', 'utf8');

console.log('Updated hash:', newHash);
console.log('Updated timestamp:', config.lastModified);
"

cd /workspaces/gmail-automation && node -e "
const config = require('./config/email-categorizer-config.json');
const relevance = config.processing_config.attribute_relevance;

console.log('Keys in attribute_relevance:', Object.keys(relevance));
console.log('\n_roles_legend structure:', Object.keys(relevance._roles_legend));
console.log('\nFirst category (financial) structure:', Object.keys(relevance.financial));
"

