const crypto = require('crypto');
const fs = require('fs');
const path = require('path');

const configPath = path.join(process.cwd(), 'config', 'email-categorizer-config.json');
const config = JSON.parse(fs.readFileSync(configPath, 'utf8'));

// Regenerate hash from processing_config
const processingConfigStr = JSON.stringify(config.processing_config, null, 2);
const newHash = crypto.createHash('sha256').update(processingConfigStr).digest('hex');

// Update hash and timestamp
config.hash = newHash;
config.lastModified = new Date().toISOString();

// Write back
fs.writeFileSync(configPath, JSON.stringify(config, null, 2) + '\n', 'utf8');

console.log('Hash updated successfully');
" && npx tsx scripts/validate-fixed-config.ts

