    60→
    61→/**
    62→ * Parse command line arguments
    63→ *
    64→ * @param args - Process arguments (excluding node and script path)
    65→ * @returns Parsed CLI arguments
    66→ * @throws Error if required arguments missing or invalid
    67→ */
    68→export function parseArguments(args: string[]): CLIArguments {
    69→  const result: Partial<CLIArguments> = {
    70→    dryRun: false,
    71→  };
    72→
    73→  for (let i = 0; i < args.length; i++) {
    74→    const arg = args[i];
    75→
    76→    switch (arg) {
    77→    case '--mode':
    78→      if (i + 1 >= args.length) {
    79→        throw new Error('Missing value for --mode argument');
    80→      }
    81→      result.mode = args[++i] as 'single' | 'batch' | 'date-range';
    82→      break;
    83→    case '--message-id':
    84→      if (i + 1 >= args.length) {
    85→        throw new Error('Missing value for --message-id argument');
    86→      }
    87→      result.messageId = args[++i];
    88→      break;
    89→    case '--limit':
    90→      if (i + 1 >= args.length) {
    91→        throw new Error('Missing value for --limit argument');
    92→      }
    93→      result.limit = parseInt(args[++i], 10);
    94→      break;
    95→    case '--start':
    96→      if (i + 1 >= args.length) {
    97→        throw new Error('Missing value for --start argument');
    98→      }
    99→      result.startDate = args[++i];
   100→      break;
   101→    case '--end':
   102→      if (i + 1 >= args.length) {
   103→        throw new Error('Missing value for --end argument');
   104→      }
   105→      result.endDate = args[++i];
   106→      break;
   107→    case '--dry-run':
   108→      result.dryRun = true;
   109→      break;
   110→    }
   111→  }
   112→
   113→  // Validate required arguments
   114→  if (!result.mode) {
   115→    throw new Error('Mode is required (--mode single|batch|date-range)');
   116→  }
   117→
   118→  if (!['single', 'batch', 'date-range'].includes(result.mode)) {
   119→    throw new Error('Invalid mode. Must be: single, batch, or date-range');
   120→  }
   121→
   122→  if (result.mode === 'single' && !result.messageId) {
   123→    throw new Error('message-id is required for single mode (--message-id <id>)');
   124→  }
   125→
   126→  if (result.mode === 'date-range') {
   127→    if (!result.startDate || !result.endDate) {
   128→      throw new Error(
   129→        'Both start and end dates are required for date-range mode (--start YYYY-MM-DD --end YYYY-MM-DD)'
   130→      );
   131→    }
   132→  }
   133→
   134→  return result as CLIArguments;
   135→}
   136→
   137→/**
   138→ * Load configuration from config directory
   139→ *
   140→ * @returns Loaded processing configuration
   141→ * @throws Error if configuration loading fails
   142→ */
   143→async function loadConfiguration(): Promise<ProcessingConfig> {
   144→  const configLoader = new ConfigurationLoader({
   145→    configDir: join(process.cwd(), 'config'),
   146→    enableHotReload: false,
   147→    validateOnLoad: true,
   148→  });
   149→
   150→  const categoryConfigResult = await configLoader.loadCategoryConfiguration();
   151→
   152→  if (!categoryConfigResult.validationPassed) {
   153→    throw new Error(`Configuration validation failed:\n${categoryConfigResult.validationErrors.join('\n')}`);
   154→  }
   155→
   156→  // Validate config exists before type assertion
   157→  if (!categoryConfigResult.config) {
   158→    throw new Error('Configuration loading returned empty config');
   159→  }
   160→
   161→  // Safely extract processing_config with type assertion
   162→  const config = categoryConfigResult.config as CategoryConfiguration;
   163→  if (!config.processing_config) {
   164→    throw new Error('Missing processing_config in category configuration');
   165→  }
   166→
   167→  return config.processing_config;
   168→}
   169→
   170→/**
   171→ * Process single email through classification pipeline
   172→ *
   173→ * @param messageId - Gmail message ID
   174→ * @param config - Processing configuration
   175→ * @param dryRun - If true, skip persistence
   176→ * @returns Processing summary
   177→ */
   178→export async function processSingleEmail(
   179→  messageId: string,
   180→  config: ProcessingConfig,
   181→  dryRun: boolean
   182→): Promise<ProcessingSummary> {
   183→  const summary: ProcessingSummary = {
   184→    totalEmails: 1,
   185→    success: 0,
   186→    errors: 0,
   187→    totalDurationMs: 0,
   188→    errorDetails: [],
   189→  };
   190→
   191→  const startTime = Date.now();
   192→
   193→  try {
   194→    // 1. Fetch email from database
