   307→
   308→  return summary;
   309→}
   310→
   311→/**
   312→ * Process emails within date range
   313→ *
   314→ * @param startDate - Start date (YYYY-MM-DD)
   315→ * @param endDate - End date (YYYY-MM-DD)
   316→ * @param limit - Maximum number of emails to process
   317→ * @param config - Processing configuration
   318→ * @param dryRun - If true, skip persistence
   319→ * @returns Processing summary
   320→ */
   321→export async function processDateRangeEmails(
   322→  startDate: string,
   323→  endDate: string,
   324→  limit: number,
   325→  config: ProcessingConfig,
   326→  dryRun: boolean
   327→): Promise<ProcessingSummary> {
   328→  const summary: ProcessingSummary = {
   329→    totalEmails: 0,
   330→    success: 0,
   331→    errors: 0,
   332→    totalDurationMs: 0,
