   378→        }
   379→
   380→        await writeExplainabilityTrace(email, result);
   381→
   382→        summary.success++;
   383→      } catch (error) {
   384→        summary.errors++;
   385→        summary.errorDetails.push({
   386→          messageId: email.id,
   387→          error: error instanceof Error ? error.message : String(error),
   388→        });
